#include <bits/stdc++.h>
using namespace std;
int main(){
    int m, n, sr, sc, newColor;
    cin >> m >> n >> sr >> sc >> newColor;
    vector<vector<int>> image(m, vector<int>(n));
    for(int i = 0; i < m; i++)
        for(int j = 0; j < n; j++)
            cin >> image[i][j];
    int oldColor = image[sr][sc];
    if (oldColor == newColor) {
        for(int i = 0; i < m; i++) {
            for(int j = 0; j < n; j++) {
                cout << image[i][j] << ' ';
            }
            cout << '\n';
        }
        return 0;
    }
    function<void(int, int)> dfs = [&](int r, int c) {
        if (0 <= r && r < m && 0 <= c && c < n && image[r][c] == oldColor) {
            image[r][c] = newColor;
            dfs(r - 1, c);
            dfs(r + 1, c);
            dfs(r, c - 1);
            dfs(r, c + 1);
        }
    };
    dfs(sr, sc);
    for(int i = 0; i < m; i++) {
        for(int j = 0; j < n; j++) {
            cout << image[i][j] << ' ';
        }
        cout << '\n';
    }
    return 0;
}
